try {
  const allItems = $input.all();
  const configNode = $('config').first();
  const fullConfig = configNode.json;
  const body = $('Webhook Call').first().json.body;
  const timezone = 'America/Sao_Paulo';
  const stepIntervalMin = 15;
  const clinicCliffHour = 20;

  const procedureId = body.procedureId || body.proceduresId;
  const procedure = fullConfig.procedures[String(procedureId)];
  const slotDurationMin = procedure.duration;
  const conflictDurationMin = procedure.isParallel ? (procedure.setupMinutes || 0) : procedure.duration;

  let allSlots = [];

  for (const item of allItems) {
    const data = item.json;
    if (data.error) continue;

    const calendarId = data.profissionalEmail;
    const professionalName = data.professionalName;
    const busy = data.calendars && data.calendars[calendarId] ? data.calendars[calendarId].busy : [];

    const busyPeriods = busy.map(b => ({
      start: new Date(b.start).getTime(),
      end: new Date(b.end).getTime()
    }));

    const defaultProv = { start_h: 8, start_m: 0, end_h: 18, end_m: 0 };
    const prof = fullConfig.professionals[calendarId] || { default: defaultProv, exceptions: {} };

    for (let d = 0; d <= 14; d++) {
      let day = new Date();
      day.setDate(day.getDate() + d);
      day.setHours(0, 0, 0, 0);
      const weekday = day.getDay();
      if (weekday === 0) continue;

      let dayRules = prof.exceptions[weekday] || prof.default;
      const datePrefix = day.toISOString().split('T')[0];
      let workStart = new Date(`${datePrefix}T${String(dayRules.start_h).padStart(2, '0')}:${String(dayRules.start_m).padStart(2, '0')}:00-03:00`);
      let workEnd = new Date(`${datePrefix}T${String(dayRules.end_h).padStart(2, '0')}:${String(dayRules.end_m).padStart(2, '0')}:00-03:00`);
      let cliffEnd = new Date(`${datePrefix}T${String(clinicCliffHour).padStart(2, '0')}:00:00-03:00`);

      let cursor = new Date(workStart);
      if (d === 0) {
        const now = new Date();
        if (now > cursor) {
          cursor = new Date(now);
          const m = cursor.getMinutes();
          cursor.setMinutes(Math.ceil(m / stepIntervalMin) * stepIntervalMin, 0, 0);
        }
      }

      while (cursor.getTime() <= workEnd.getTime()) {
        const slotStart = cursor.getTime();
        const slotEndTotal = slotStart + slotDurationMin * 60000;
        const slotEndForConflict = slotStart + conflictDurationMin * 60000;

        if (slotEndTotal > cliffEnd.getTime()) break;

        const isBusy = conflictDurationMin > 0 ? busyPeriods.some(b => (slotStart < b.end && slotEndForConflict > b.start)) : false;

        if (!isBusy) {
          allSlots.push({
            iso: cursor.toLocaleString('sv-SE', { timeZone: timezone }).replace(' ', 'T') + '-03:00',
            display: cursor.toLocaleString('pt-BR', {
              timeZone: timezone,
              weekday: 'short', day: 'numeric', month: 'short',
              hour: '2-digit', minute: '2-digit'
            }) + ` (${professionalName})`,
            professional: professionalName,
            profissional: professionalName
          });
        }
        cursor = new Date(cursor.getTime() + stepIntervalMin * 60000);
      }
    }
  }

  allSlots.sort((a, b) => new Date(a.iso) - new Date(b.iso));
  return [{ json: { availableSlots: allSlots } }];
} catch (e) {
  return [{ json: { error: true, message: e.message } }];
}

