try {
  const body = $('Webhook Call').first().json.body;
  const configNode = $('config').first();
  if (!configNode) return [{ json: { error: true, message: 'Config not found' } }];
  const fullConfig = configNode.json;
  const requestedProf = body.profissional || body.employeeEmail;
  const procedureId = body.procedureId || body.proceduresId;

  if (requestedProf) {
    let name = requestedProf;
    let email = requestedProf;
    for (const [e, p] of Object.entries(fullConfig.professionals)) {
      if (e === requestedProf || p.name === requestedProf) {
        email = e;
        name = p.name;
        break;
      }
    }
    return [{ json: { profissionalEmail: email, professionalName: name } }];
  }

  const procedure = fullConfig.procedures[String(procedureId)];
  if (!procedure) {
    return [{ json: { error: true, message: `Procedimento inválido (ID: ${procedureId})`, statusCode: 404 } }];
  }

  const responsibleNames = procedure.responsible || [];
  const results = [];

  for (const name of responsibleNames) {
    const email = Object.keys(fullConfig.professionals).find(e => fullConfig.professionals[e].name === name);
    if (email) {
      results.push({ json: { professionalEmail: email, professionalName: name } });
    }
  }

  if (results.length === 0) {
    return [{ json: { error: true, message: 'Nenhum profissional disponível para este procedimento.' } }];
  }

  return results;
} catch (e) {
  return [{ json: { error: true, message: e.message } }];
}

try {
  const input = $input.first().json;
  const entry = $('Webhook Call').first().json.body;
  const configNode = $('config').first();
  if (!configNode) return [{ json: { error: true, message: 'Node config não encontrado ou sem dados.' } }];
  const fullConfig = configNode.json;
  const calendarId = entry.profissional || entry.employeeEmail;

  const busy = input.calendars[calendarId]?.busy || [];
  const startTimeStr = entry.startTime;

  const procedureId = entry.procedureId || entry.proceduresId;
  const procedure = fullConfig.procedures[String(procedureId)];
  if (!procedure) {
    return [{ json: { slotFree: false, message: `Procedimento inválido ou não encontrado (ID: ${procedureId})`, statusCode: 404 } }];
  }
  const slotDurationMin = procedure.duration;
  const conflictDurationMin = procedure.isParallel ? (procedure.setupMinutes || 0) : procedure.duration;
  const stepIntervalMin = 15;
  const timezone = 'America/Sao_Paulo';

  const defaultProv = { start_h: 8, start_m: 0, end_h: 18, end_m: 0 };
  const prof = (fullConfig.professionals && calendarId && fullConfig.professionals[calendarId]) ? fullConfig.professionals[calendarId] : { default: defaultProv, exceptions: {} };

  const clinicCliffHour = 20;
  const selectedDate = new Date(startTimeStr);
  const selectedStart = selectedDate.getTime();
  const selectedEnd = selectedStart + slotDurationMin * 60000;
  const conflictEnd = selectedStart + conflictDurationMin * 60000;

  function generateSlots() {
    const now = new Date();
    const slots = [];
    const busyPeriods = busy.map(b => ({ start: new Date(b.start).getTime(), end: new Date(b.end).getTime() }));

    for (let d = 0; d <= 14; d++) {
      let day = new Date();
      day.setDate(day.getDate() + d);
      day.setHours(0, 0, 0, 0);
      const weekday = day.getDay();
      if (weekday === 0) continue;

      let dayRules = prof.exceptions[weekday] || prof.default;
      const datePrefix = day.toISOString().split('T')[0];
      let workStart = new Date(`${datePrefix}T${String(dayRules.start_h).padStart(2, '0')}:${String(dayRules.start_m).padStart(2, '0')}:00-03:00`);
      let workEnd = new Date(`${datePrefix}T${String(dayRules.end_h).padStart(2, '0')}:${String(dayRules.end_m).padStart(2, '0')}:00-03:00`);
      let cliffEnd = new Date(`${datePrefix}T${String(clinicCliffHour).padStart(2, '0')}:00:00-03:00`);

      let cursor = new Date(workStart);
      if (d === 0 && now > workStart) {
        cursor = new Date(now);
        const m = cursor.getMinutes();
        cursor.setMinutes(Math.ceil(m / stepIntervalMin) * stepIntervalMin, 0, 0);
      }

      while (cursor.getTime() <= workEnd.getTime()) {
        const slotStart = cursor.getTime();
        const slotEndTotal = slotStart + slotDurationMin * 60000;
        const slotEndForConflict = slotStart + conflictDurationMin * 60000;
        if (slotEndTotal > cliffEnd.getTime()) break;

        const isBusy = conflictDurationMin > 0 ? busyPeriods.some(b => (slotStart < b.end && slotEndForConflict > b.start)) : false;
        if (!isBusy) {
          slots.push({
            iso: cursor.toLocaleString('sv-SE', { timeZone: timezone }).replace(' ', 'T') + '-03:00',
            display: cursor.toLocaleString('pt-BR', { timeZone: timezone, weekday: 'short', day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' })
          });
        }
        cursor = new Date(cursor.getTime() + stepIntervalMin * 60000);
      }
    }
    return slots;
  }

  const conflict = conflictDurationMin > 0 ? busy.find(b => {
    const bStart = new Date(b.start).getTime();
    const bEnd = new Date(b.end).getTime();
    return (selectedStart < bEnd && conflictEnd > bStart);
  }) : null;

  if (conflict) {
    return [{
      json: {
        slotFree: false,
        message: "Este horário acabou de ser ocupado. Aqui estão novas opções:",
        availableSlots: generateSlots()
      }
    }];
  }

  const finalEndISO = new Date(selectedEnd).toLocaleString('sv-SE', { timeZone: timezone }).replace(' ', 'T') + '-03:00';
  return [{
    json: {
      slotFree: true,
      startTime: startTimeStr,
      endTime: finalEndISO,
      procedureName: procedure.name
    }
  }];
} catch (e) {
  return [{ json: { error: true, message: e.message } }];
}
